# OEIS sequence: A394611

def sequence(N=100):
    a = [0]  # a(1) = 0
    for n in range(1, N):
        target = a[n - 1]  # a(n)
        count = 0
        # count pairs (i < j) with i,j in [0..n-1]
        for i in range(n):
            for j in range(i + 1, n):
                if a[i] + a[j] == target:
                    count += 1
        a.append(count)
    return a
seq = sequence(100)
print(seq)

